package tools.jackson.core.json;

import java.io.IOException;
import java.io.InputStream;

import tools.jackson.core.Base64Variant;
import tools.jackson.core.JacksonException;
import tools.jackson.core.SerializableString;
import tools.jackson.core.io.CharTypes;
import tools.jackson.core.io.CharacterEscapes;
import tools.jackson.core.io.IOContext;

/**
 * Helper class that encapsulates the logic for UTF-8 character encoding,
 * escaping, and Base64 encoding, operating on a provided byte buffer.
 * This class does not manage the output buffer or stream directly, but
 * operates on them as passed parameters.
 */
public final class UTF8WriterDelegate {
    private final static byte BYTE_u = (byte) 'u';
    private final static byte BYTE_0 = (byte) '0';
    private final static byte BYTE_BACKSLASH = (byte) '\\';

    private final static byte[] HEX_BYTES_UPPER = CharTypes.copyHexBytes(true);
    private final static byte[] HEX_BYTES_LOWER = CharTypes.copyHexBytes(false);

    // Intermediate copies only made up to certain length...
    private final static int MAX_BYTES_TO_BUFFER = 512;

    // Surrogate pair constants (from JsonGeneratorBase)
    private final static int SURR1_FIRST = 0xD800;
    private final static int SURR1_LAST = 0xDBFF;
    private final static int SURR2_FIRST = 0xDC00;
    private final static int SURR2_LAST = 0xDFFF;

    protected final IOContext _ioContext;

    // Configuration for escaping, set by UTF8JsonGenerator
    protected int[] _outputEscapes;
    protected CharacterEscapes _characterEscapes;
    protected int _maximumNonEscapedChar;
    protected int _formatWriteFeatures; // For JsonWriteFeature.COMBINE_UNICODE_SURROGATES_IN_UTF8
    protected boolean _cfgWriteHexUppercase; // For getHexBytes()

    public UTF8WriterDelegate(IOContext ioCtxt,
            int[] outputEscapes, CharacterEscapes characterEscapes, int maximumNonEscapedChar,
            int formatWriteFeatures, boolean cfgWriteHexUppercase)
    {
        _ioContext = ioCtxt;
        _outputEscapes = outputEscapes;
        _characterEscapes = characterEscapes;
        _maximumNonEscapedChar = maximumNonEscapedChar;
        _formatWriteFeatures = formatWriteFeatures;
        _cfgWriteHexUppercase = cfgWriteHexUppercase;
    }

    // --- Configuration setters (called by UTF8JsonGenerator) ---
    public void setCharacterEscapes(CharacterEscapes esc) { _characterEscapes = esc; }
    public void setOutputEscapes(int[] esc) { _outputEscapes = esc; }
    public void setMaximumNonEscapedChar(int max) { _maximumNonEscapedChar = max; }
    public void setFormatWriteFeatures(int features) { _formatWriteFeatures = features; }
    public void setWriteHexUppercase(boolean uppercase) { _cfgWriteHexUppercase = uppercase; }

    // --- Public methods for UTF8JsonGenerator to call ---

    /**
     * Writes a byte array to the output buffer. If the buffer is too small,
     * it writes directly to the output stream.
     *
     * @param bytes The byte array to write.
     * @param offset Offset in the byte array.
     * @param len Length to write from the byte array.
     * @param outputBuffer The output buffer.
     * @param outputTail Current tail position in the output buffer.
     * @param outputEnd End position of the output buffer.
     * @param outputStream The underlying output stream for direct writes.
     * @return The new outputTail position.
     * @throws JacksonException
     */
    public int writeBytes(byte[] bytes, int offset, int len, byte[] outputBuffer, int outputTail, int outputEnd, OutputStream outputStream) throws JacksonException {
        // This method assumes UTF8JsonGenerator has already flushed if (outputTail + len) > outputEnd
        // If it still doesn't fit, write directly to stream.
        if (len > MAX_BYTES_TO_BUFFER) {
            try {
                outputStream.write(bytes, offset, len);
