                if (_isStartOfSurrogatePair(ch)) {
                    final boolean combineSurrogates = JsonWriteFeature.COMBINE_UNICODE_SURROGATES_IN_UTF8.enabledIn(_formatWriteFeatures);
                    if (combineSurrogates && offset < end) {
                        char highSurrogate = (char) ch;
                        char lowSurrogate = cbuf[offset];
                        if (_isEndOfSurrogatePair(lowSurrogate)) {
                            offset++;
                            outputPtr = _outputSurrogatePair(highSurrogate, lowSurrogate, outputPtr, outputBuffer, outputEnd, outputStream);
                            continue;
                        }
                    }
                }
                outputPtr = _outputMultiByteChar(ch, outputPtr, outputBuffer, outputEnd, outputStream);
            }
        }
        return outputPtr;
    }

    private int _writeCustomStringSegment2(final String text, int offset, final int end, byte[] outputBuffer, int outputPtr, int outputEnd, OutputStream outputStream) throws JacksonException {
        // UTF8JsonGenerator must flush if needed before calling this.
        final int[] escCodes = _outputEscapes;
        final int maxUnescaped = (_maximumNonEscapedChar <= 0) ? 0xFFFF : _maximumNonEscapedChar;
        final CharacterEscapes customEscapes = _characterEscapes; // non-null

        while (offset < end) {
            int ch = text.charAt(offset++);
            if (ch <= 0x7F) {
                 if (escCodes[ch] == 0) {
                     outputBuffer[outputPtr++] = (byte) ch;
                     continue;
                 }
                 int escape = escCodes[ch];
                 if (escape > 0) { // 2-char escape, fine
                     outputBuffer[outputPtr++] = BYTE_BACKSLASH;
                     outputBuffer[outputPtr++] = (byte) escape;
                 } else if (escape == CharacterEscapes.ESCAPE_CUSTOM) {
                     SerializableString esc = customEscapes.getEscapeSequence(ch);
                     if (esc == null) {
                         _ioContext.reportError("Invalid custom escape definitions; custom escape not found for character code 0x"
                                 +Integer.toHexString(ch)+", although was supposed to have one");
                     }
                     outputPtr = _writeCustomEscape(outputBuffer, outputPtr, esc, end-offset, outputEnd, outputStream);
                 } else {
                     // ctrl-char, 6-byte escape...
                     outputPtr = _writeGenericEscape(ch, outputPtr, outputBuffer, outputEnd, outputStream);
                 }
                 continue;
            }
            if (ch > maxUnescaped) { // [JACKSON-102] Allow forced escaping if non-ASCII (etc) chars:
                outputPtr = _writeGenericEscape(ch, outputPtr, outputBuffer, outputEnd, outputStream);
                continue;
            }
            SerializableString esc = customEscapes.getEscapeSequence(ch);
            if (esc != null) {
                outputPtr = _writeCustomEscape(outputBuffer, outputPtr, esc, end-offset, outputEnd, outputStream);
                continue;
            }
            if (ch <= 0x7FF) { // fine, just needs 2 byte output
                outputBuffer[outputPtr++] = (byte) (0xc0 | (ch >> 6));
                outputBuffer[outputPtr++] = (byte) (0x80 | (ch & 0x3f));
            } else {
                // 3- or 4-byte character
                if (_isStartOfSurrogatePair(ch)) {
                    final boolean combineSurrogates = JsonWriteFeature.COMBINE_UNICODE_SURROGATES_IN_UTF8.enabledIn(_formatWriteFeatures);
                    if (combineSurrogates && offset < end) {
                        char highSurrogate = (char) ch;
                        char lowSurrogate = text.charAt(offset);
                        if (_isEndOfSurrogatePair(lowSurrogate)) {
                            offset++;
                            outputPtr = _outputSurrogatePair(highSurrogate, lowSurrogate, outputPtr, outputBuffer, outputEnd, outputStream);
                            continue;
                        }
                    }
                }
                outputPtr = _outputMultiByteChar(ch, outputPtr, outputBuffer, outputEnd, outputStream);
            }
        }
        return outputPtr;
    }

    private int _writeCustomEscape(byte[] outputBuffer, int outputPtr, SerializableString esc, int remainingChars, int outputEnd, OutputStream outputStream)
        throws JacksonException
    {
        byte[] raw = esc.asUnquotedUTF8(); // must be escaped at this point, shouldn't double-quote
        int len = raw.length;
        if (len > 6) { // may violate constraints we have, do offline
            return _handleLongCustomEscape(outputBuffer, outputPtr, outputEnd, raw, remainingChars, outputStream);
        }
        // otherwise will fit without issues, so:
        System.arraycopy(raw, 0, outputBuffer, outputPtr, len);
        return (outputPtr + len);
    }

    private int _handleLongCustomEscape(byte[] outputBuffer, int outputPtr, int outputEnd,
            byte[] raw, int remainingChars, OutputStream outputStream)
        throws JacksonException
    {
        final int len = raw.length;
        if ((outputPtr + len) > outputEnd) {
            // UTF8JsonGenerator must flush here
            throw _ioContext.constructWriteException("Output buffer overflow during custom escape (flush required)");
        }
        System.arraycopy(raw, 0, outputBuffer, outputPtr, len);
        outputPtr += len;
        // but is the invariant still obeyed? If not, flush once more
        if ((outputPtr +  6 * remainingChars) > outputEnd) {
            // UTF8JsonGenerator must flush here
            throw _ioContext.constructWriteException("Output buffer overflow during custom escape (flush required)");
        }
        return outputPtr;
    }

    private int _writeUTF8Segment2(final byte[] utf8, int offset, int len, byte[] outputBuffer, int outputPtr, int outputEnd, OutputStream outputStream)
        throws JacksonException
    {
        // UTF8JsonGenerator must flush if needed before calling this.
        final int[] escCodes = _outputEscapes;
        len += offset; // so 'len' becomes 'end'

        while (offset < len) {
            byte b = utf8[offset++];
            int ch = b;
            if (ch < 0 || escCodes[ch] == 0) {
                outputBuffer[outputPtr++] = b;
                continue;
            }
            int escape = escCodes[ch];
            if (escape > 0) { // 2-char escape, fine
                outputBuffer[outputPtr++] = BYTE_BACKSLASH;
                outputBuffer[outputPtr++] = (byte) escape;
            } else {
                // ctrl-char, 6-byte escape...
                outputPtr = _writeGenericEscape(ch, outputPtr, outputBuffer, outputEnd, outputStream);
            }
        }
        return outputPtr;
    }

    private int _readMore(InputStream in,
            byte[] readBuffer, int inputPtr, int inputEnd,
            int maxRead) throws JacksonException
    {
        // anything to shift to front?
        int i = 0;
        while (inputPtr < inputEnd) {
            readBuffer[i++]  = readBuffer[inputPtr++];
        }
        inputPtr = 0;
        inputEnd = i;
        maxRead = Math.min(maxRead, readBuffer.length);

        do {
            int length = maxRead - inputEnd;
            if (length == 0) {
                break;
            }
            int count;
            try {
                count = in.read(readBuffer, inputEnd, length);
            } catch (IOException e) {
                throw _ioContext.constructWriteException(e);
            }
            if (count < 0) {
                return inputEnd;
            }
            inputEnd += count;
        } while (inputEnd < 3);
        return inputEnd;
    }

    /**
     * Method called to output a character that is beyond range of
     * 1- and 2-byte UTF-8 encodings, when outputting "raw"
     * text (meaning it is not to be escaped or quoted)
     *
     * @param ch Character to output.
     * @param cbuf Character buffer (may be null if single char).
     * @param inputOffset Current input offset in cbuf.
     * @param inputEnd End of input in cbuf.
     * @param outputBuffer The output buffer.
     * @param outputPtr Current tail position in the output buffer.
     * @param outputEnd End position of the output buffer.
     * @param outputStream The underlying output stream (for error reporting).
     * @return An int array: [newOutputTail, newInputOffset].
     * @throws JacksonException
     */
    private int[] _outputRawMultiByteChar(int ch, char[] cbuf, int inputOffset, int inputEnd, byte[] outputBuffer, int outputPtr, int outputEnd, OutputStream outputStream)
        throws JacksonException
    {
        // Let's handle surrogates gracefully (as 4 byte output):
        if (ch >= SURR1_FIRST) {
            if (ch <= SURR2_LAST) { // yes, outside of BMP
                // Do we have second part?
                if (inputOffset >= inputEnd || cbuf == null) { // nope... have to note down
                    _ioContext.reportError(String.format(
"Split surrogate on writeRaw() input (last character): first character 0x%4x", ch));
                } else {
                    outputPtr = _outputSurrogates(ch, cbuf[inputOffset], outputBuffer, outputPtr, outputEnd, outputStream);
                }
                return new int[] { outputPtr, inputOffset + 1 }; // <-- returns new inputOffset
            }
        }
        outputBuffer[outputPtr++] = (byte) (0xe0 | (ch >> 12));
        outputBuffer[outputPtr++] = (byte) (0x80 | ((ch >> 6) & 0x3f));
        outputBuffer[outputPtr++] = (byte) (0x80 | (ch & 0x3f));
        return new int[] { outputPtr, inputOffset }; // <-- returns inputOffset unchanged
    }

    protected int _outputSurrogates(int surr1, int surr2, byte[] outputBuffer, int outputPtr, int outputEnd, OutputStream outputStream) throws JacksonException {
        int c = _decodeSurrogate(surr1, surr2);
        // UTF8JsonGenerator must flush if needed before calling this.
        outputBuffer[outputPtr++] = (byte) (0xf0 | (c >> 18));
        outputBuffer[outputPtr++] = (byte) (0x80 | ((c >> 12) & 0x3f));
        outputBuffer[outputPtr++] = (byte) (0x80 | ((c >> 6) & 0x3f));
        outputBuffer[outputPtr++] = (byte) (0x80 | (c & 0x3f));
        return outputPtr;
    }

    private int _outputSurrogatePair(char highSurrogate, char lowSurrogate, int outputPtr, byte[] outputBuffer, int outputEnd, OutputStream outputStream) {
        final int unicode = 0x10000 + ((highSurrogate & 0x03FF) << 10)
                + (lowSurrogate & 0x03FF);

        outputBuffer[outputPtr++] = (byte) (0xF0 + ((unicode >> 18) & 0x07));
        outputBuffer[outputPtr++] = (byte) (0x80 + ((unicode >> 12) & 0x3F));
        outputBuffer[outputPtr++] = (byte) (0x80 + ((unicode >> 6) & 0x3F));
        outputBuffer[outputPtr++] = (byte) (0x80 + (unicode & 0x3F));

        return outputPtr;
    }

    private int _outputMultiByteChar(int ch, int outputPtr, byte[] outputBuffer, int outputEnd, OutputStream outputStream) throws JacksonException {
        byte[] HEX_CHARS = getHexBytes();
        if (ch >= SURR1_FIRST && ch <= SURR2_LAST) { // yes, outside of BMP; add an escape
                outputBuffer[outputPtr++] = BYTE_BACKSLASH;
                outputBuffer[outputPtr++] = BYTE_u;

                outputBuffer[outputPtr++] = HEX_CHARS[(ch >> 12) & 0xF];
                outputBuffer[outputPtr++] = HEX_CHARS[(ch >> 8) & 0xF];
                outputBuffer[outputPtr++] = HEX_CHARS[(ch >> 4) & 0xF];
                outputBuffer[outputPtr++] = HEX_CHARS[ch & 0xF];
        } else {
            outputBuffer[outputPtr++] = (byte) (0xe0 | (ch >> 12));
            outputBuffer[outputPtr++] = (byte) (0x80 | ((ch >> 6) & 0x3f));
            outputBuffer[outputPtr++] = (byte) (0x80 | (ch & 0x3f));
        }
        return outputPtr;
    }

    /**
     * Method called to write a generic Unicode escape for given character.
     *
     * @param charToEscape Character to escape using escape sequence (\\uXXXX)
     * @param outputPtr Position within output buffer to append escape sequence
     * @param outputBuffer The output buffer.
     * @param outputEnd End position of the output buffer.
     * @param outputStream The underlying output stream (for error reporting).
     * @return New output position after appending
     * @throws JacksonException
     */
    private int _writeGenericEscape(int charToEscape, int outputPtr, byte[] outputBuffer, int outputEnd, OutputStream outputStream) throws JacksonException {
        byte[] HEX_CHARS = getHexBytes();
        outputBuffer[outputPtr++] = BYTE_BACKSLASH;
        outputBuffer[outputPtr++] = BYTE_u;
        if (charToEscape > 0xFF) {
            int hi = (charToEscape >> 8) & 0xFF;
            outputBuffer[outputPtr++] = HEX_CHARS[hi >> 4];
            outputBuffer[outputPtr++] = HEX_CHARS[hi & 0xF];
            charToEscape &= 0xFF;
        } else {
            outputBuffer[outputPtr++] = BYTE_0;
            outputBuffer[outputPtr++] = BYTE_0;
        }
        // We know it's a control char, so only the last 2 chars are non-0
        outputBuffer[outputPtr++] = HEX_CHARS[charToEscape >> 4];
        outputBuffer[outputPtr++] = HEX_CHARS[charToEscape & 0xF];
        return outputPtr;
    }

    private byte[] getHexBytes() {
        return _cfgWriteHexUppercase ? HEX_BYTES_UPPER : HEX_BYTES_LOWER;
    }

    private static boolean _isStartOfSurrogatePair(final int ch) {
        // In 0xD800 - 0xDBFF range?
        return (ch & 0xFC00) == 0xD800;
    }

    private static boolean _isEndOfSurrogatePair(final int ch) {
        // In 0xDC00 - 0xDFFF range?
        return (ch & 0xFC00) == 0xDC00;
    }

    // This method is from JsonGeneratorBase, needs to be accessible or re-implemented
    protected int _decodeSurrogate(int surr1, int surr2) throws JacksonException {
        // First, must be valid first surrogate
        if (surr2 < SURR2_FIRST || surr2 > SURR2_LAST) {
            _ioContext.reportError(String.format(
                    "Incomplete surrogate pair: first char 0x%4x, second 0x%4x",
                    surr1, surr2));
        }
        int c = 0x10000 + ((surr1 - SURR1_FIRST) << 10) + (surr2 - SURR2_FIRST);
        return c;
    }
}
